UPDATE event.notice
SET  title          = #{title}
    ,content        = #{content}
    ,top_yn         = #{topYn}
    ,use_yn         = #{useYn}
    ,file_seq       = #{fileSeq}
    ,upt_user_seq   = #{uptUserSeq}
    ,upt_date_time  = CURRENT_TIMESTAMP
WHERE notice_seq = #{noticeSeq}
